#!/usr/bin/env python3

import sys
import os
import subprocess
import datetime

def usage():
    print("Usage: backup.py <directory_path> <format>")
    print("Supported formats: tar.gz, tar.bz2, zip, 7z")
    sys.exit(1)

def create_backup(directory, fmt):
    if not os.path.isdir(directory):
        print(f"Error: Directory '{directory}' does not exist.")
        sys.exit(1)

    base_name = os.path.basename(os.path.abspath(directory.rstrip('/')))
    timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
    archive_name = f"{base_name}_{timestamp}"

    if fmt == 'tar.gz':
        archive_file = f"{archive_name}.tar.gz"
        cmd = ['tar', '-czf', archive_file, '-C', os.path.dirname(directory), base_name]
    elif fmt == 'tar.bz2':
        archive_file = f"{archive_name}.tar.bz2"
        cmd = ['tar', '-cjf', archive_file, '-C', os.path.dirname(directory), base_name]
    elif fmt == 'zip':
        archive_file = f"{archive_name}.zip"
        cmd = ['zip', '-r', archive_file, base_name]
        os.chdir(os.path.dirname(directory))
    elif fmt == '7z':
        archive_file = f"{archive_name}.7z"
        cmd = ['7z', 'a', archive_file, base_name]
        os.chdir(os.path.dirname(directory))
    else:
        print(f"Error: Unsupported format '{fmt}'")
        usage()

    try:
        subprocess.check_call(cmd)
        print(f"Backup created: {archive_file}")
    except subprocess.CalledProcessError as e:
        print(f"Error creating backup: {e}")
        sys.exit(1)

if __name__ == '__main__':
    if len(sys.argv) != 3:
        usage()

    dir_path = sys.argv[1]
    format_type = sys.argv[2].lower()
    create_backup(dir_path, format_type)